INSERT INTO combination_rule (ingredient_a, ingredient_b, condition_desc, safe_concentration_a, required_concentration_b, explanation, source)
VALUES
    ('METHYLPARABEN', 'PROPYLPARABEN', 'Combined parabens must not exceed 0.8% total', 0.4, 0.14, 'When both parabens are present, total concentration of all parabens (as acid) must not exceed 0.8%. Individual limits also apply.', 'EU Reg. (EC) 1223/2009, Annex V/12'),
    ('SODIUM LAURYL SULFATE', 'METHYLISOTHIAZOLINONE', 'SLS enhances penetration of sensitizing preservatives', 1.0, 0.0015, 'SLS disrupts skin barrier, increasing penetration of MIT. Combined use increases sensitization risk significantly.', 'SCCS/1521/13'),
    ('SALICYLIC ACID', 'GLYCOLIC ACID', 'Dual acid combination — pH and total concentration critical', 2.0, 4.0, 'Combined AHA/BHA increases exfoliation intensity. Total acid concentration must be managed; pH must remain >= 3.5.', 'SCCS/1629/21'),
    ('METHYLCHLOROISOTHIAZOLINONE', 'METHYLISOTHIAZOLINONE', 'Must be used in 3:1 ratio; max combined 0.0015%', 0.0015, 0.0015, 'MCI and MIT must be used together in 3:1 ratio (MCI:MIT). Maximum combined concentration 0.0015% in rinse-off only.', 'EU Reg. Annex V/39'),
    ('PHENOXYETHANOL', 'ETHYLHEXYLGLYCERIN', 'Synergistic preservative system', 1.0, NULL, 'Ethylhexylglycerin boosts phenoxyethanol''s antimicrobial activity. This allows lower effective concentrations. No violation — beneficial combination.', 'Cosmetic preservation best practices'),
    ('SODIUM HYDROXIDE', 'HYDROGEN PEROXIDE', 'Strongly reactive combination', 5.0, 12.0, 'NaOH and H2O2 together cause exothermic reaction. Must be carefully buffered in hair treatments. pH and concentration controls essential.', 'SCCS/1553/15'),
    ('RETINOL', 'SALICYLIC ACID', 'Increased irritation potential', 0.3, 2.0, 'Retinol combined with Salicylic Acid significantly increases skin irritation and photosensitivity. Not recommended in same leave-on product.', 'Dermatological consensus / SCCS opinion'),
    ('RETINOL', 'GLYCOLIC ACID', 'Increased irritation and photosensitivity', 0.3, 4.0, 'AHA + Retinoid combination dramatically increases skin irritation. Should not be used in same leave-on product.', 'Dermatological consensus'),
    ('FORMALDEHYDE', 'DMDM HYDANTOIN', 'Double formaldehyde exposure', NULL, 0.6, 'DMDM Hydantoin releases formaldehyde. If free formaldehyde is also present, combined exposure far exceeds safe limits.', 'EU Reg. Annex II/1577 + Annex V/13'),
    ('TRICLOSAN', 'SODIUM LAURYL SULFATE', 'Enhanced systemic absorption', 0.3, 1.0, 'SLS increases dermal penetration of Triclosan, raising concerns about endocrine disruption at sub-threshold concentrations.', 'Environmental Health Perspectives'),
    ('ZINC PYRITHIONE', 'SELENIUM DISULFIDE', 'Incompatible anti-dandruff actives', 1.0, 1.0, 'Both are anti-dandruff actives with different mechanisms. Combined use provides no benefit and increases scalp irritation.', 'Dermatological formulary guidance'),
    ('BENZALKONIUM CHLORIDE', 'SODIUM LAURYL SULFATE', 'Cationic-anionic incompatibility', 0.1, 1.0, 'Cationic (BAC) and anionic (SLS) surfactants form insoluble precipitates, reducing efficacy of both and causing product instability.', 'Surfactant chemistry principles'),
    ('SALICYLIC ACID', 'LACTIC ACID', 'Dual acid combination — enhanced exfoliation risk', 2.0, 2.5, 'BHA + AHA combination lowers effective pH significantly. Combined use increases irritation potential. Monitor total acid concentration and pH.', 'SCCS guidance on AHA/BHA products'),
    ('SODIUM LAURYL SULFATE', 'DIMETHICONE', 'Surfactant-silicone interaction in shampoos', 1.0, NULL, 'SLS can strip silicone buildup but also increases scalp dryness. High SLS with heavy silicones may cause residue buildup requiring clarifying.', 'Cosmetic chemistry formulation guidance'),
    ('BUTYLPHENYL METHYLPROPIONAL', 'LINALOOL', 'Double fragrance allergen exposure', NULL, NULL, 'Both are significant fragrance allergens. Combined presence increases risk of contact sensitization. Butylphenyl methylpropional (Lilial) is now prohibited in EU.', 'SCCS/1459/11 + EU Reg. Annex II/1666');
